  ('elementary-f29af906-moex-00708', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例之規定，下列何類土地，除零星夾雜難以避免者外，不得徵收？', '["一般農業區乙種建築用地", "特定農業區乙種建築用地", "一般農業區農牧用地", "特定農業區農牧用地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00709', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依所得稅法之規定，總機構在中華民國境內之營利事業持有房屋、土地之期間及其交易所得稅率，下列 敘述何者正確？', '["在二年以內者，稅率為百分之四十", "超過二年，未逾五年者，稅率為百分之三十", "超過五年者，稅率為百分之二十", "超過十年者，稅率為百分之十五"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00710', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依房屋稅條例之規定，房屋遇有焚燬、坍塌、拆除至不堪居住程度者，應由納稅義務人申報當地主管稽 徵機關查實後，在多久時間內，停止課稅？', '["六個月", "一年", "一年六個月", "未重建完成期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00711', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，關於土地增值稅，下列敘述何者錯誤？', '["私人捐贈供興辦社會福利事業使用之土地，於符合一定要件下，免徵土地增值稅", "配偶相互贈與之土地，免徵土地增值稅", "被徵收之土地，免徵其土地增值稅", "作農業使用之農業用地，移轉與自然人時，得申請不課徵土地增值稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00712', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於照價收買土地之地價，依下列何者規定為計算依據？', '["舉辦規定地價或重新規定地價時，申報之地價未滿公告地價百分之八十時，以其公告地價為準", "土地所有權移轉或設定典權時，申報之移轉現值經審核低於公告土地現值者，以其申報土地移轉現值 為準", "農業用地閒置不用，經加徵荒地稅滿三年，仍不使用者，以收買當期之市價為準", "超額土地，逾期未出售或未建築使用者，以收買當期之公告地價為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00713', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，買賣案件於申請所有權移轉登記時，由誰檢附申報書共同向直轄市、縣（市） 主管機關申報登錄土地及建物成交案件實際資訊？', '["權利人", "義務人", "不動產經紀人", "權利人及義務人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00714', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，地價調查，應抽查最近二年內土地①價格或②價格，以為查定標準地價之依據：', '["", "公告土地現值，", "收益價格", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00715', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於用益物權之定義，下列敘述何者錯誤？', '["普通地上權者，謂以在他人土地之上下有建築物或其他工作物為目的而使用其土地之權", "區分地上權者，謂以在他人土地上下之全部空間範圍內設定之地上權", "農育權者，謂在他人土地為農作、森林、養殖、畜牧、種植竹木或保育之權", "不動產役權者，謂以他人不動產供自己不動產通行、汲水、採光、眺望、電信或其他以特定便宜之用 為目的之權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00716', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '市地重劃共同負擔之費用負擔包括工程費用，則工程費用包含下列那些項目？', '["國民小學之規劃設計、施工、整地、材料、工程管理費用及應徵收之空氣污染防制費", "國民中學之規劃設計、施工、整地、材料、工程管理費用及應徵收之空氣污染防制費", "平面停車場之規劃設計、施工、整地、材料、工程管理費用及應徵收之空氣污染防制費", "零售市場之規劃設計、施工、整地、材料、工程管理費用及應徵收之空氣污染防制費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00717', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依非都市土地使用管制規則之規定，依工廠管理輔導法所辦理使用地變更編定之特定目的事業用地，其 建蔽率不得超過多少？', '["百分之六十", "百分之七十", "百分之五十", "百分之八十"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
